/**
 * Read warp markers of an audio clip. Clip.warp_markers returns a Dict with
 * pairs of sample_time / beat_time. Same Live 12 vs 11 envelope situation
 * as the note Dict ops — use _dictReturnToJson.
 *
 * @param {number} id
 * @param {number} trackIndex
 * @param {number} slotIndex
 */
function lom_get_warp_markers(id, trackIndex, slotIndex) {
  _handle(id, function () {
    var c = new LiveAPI(null, _clipPath(trackIndex, slotIndex));
    var raw = c.get('warp_markers');
    var val = Array.isArray(raw) && raw.length === 1 ? raw[0] : raw;
    if (typeof val === 'string' && val.charAt(0) === '{') {
      // Live 12+: JSON string envelope. Unwrap the {warp_markers: ...} key.
      try {
        var parsed = JSON.parse(val);
        return JSON.stringify(parsed.warp_markers !== undefined ? parsed.warp_markers : parsed);
      } catch (_) {}
    }
    // Fallback: try the Dict-name pattern (older Live).
    return _dictReturnToJson(raw);
  });
}

