/**
 * Read chain props (regular Rack chain or DrumPad chain — same Chain class).
 *
 * @param {string} chainPath
 * @param {number} chainIdx
 * @returns {object}
 */
function _readChain(chainPath, chainIdx) {
  var c = new LiveAPI(null, chainPath);
  return {
    chain_idx: chainIdx,
    name: String(_unwrap(c.get('name')) || ''),
    color: parseInt(_unwrap(c.get('color'))),
    mute: Boolean(parseInt(_unwrap(c.get('mute')))),
    solo: Boolean(parseInt(_unwrap(c.get('solo')))),
    muted_via_solo: Boolean(parseInt(_unwrap(c.get('muted_via_solo')))),
    has_audio_input: Boolean(parseInt(_unwrap(c.get('has_audio_input')))),
    has_audio_output: Boolean(parseInt(_unwrap(c.get('has_audio_output')))),
    has_midi_input: Boolean(parseInt(_unwrap(c.get('has_midi_input')))),
    has_midi_output: Boolean(parseInt(_unwrap(c.get('has_midi_output')))),
  };
}

/**
 * Outlet JSON list of chains in a regular Rack (Audio Effect Rack, Instrument
 * Rack). Returns [] for Drum Racks (use lom_get_drum_pads instead) or
 * non-rack devices.
 *
 * @param {number} id
 * @param {number} track
 * @param {number} devIdx
 */
function lom_get_rack_chains(id, track, devIdx) {
  _handle(id, function () {
    var rack = new LiveAPI(null, _rackPath(track, devIdx));
    var count = parseInt(rack.getcount('chains'));
    var out = [];
    for (var i = 0; i < count; i++) {
      out.push(_readChain(_chainPath(track, devIdx, i), i));
    }
    return JSON.stringify(out);
  });
}

/**
 * Outlet JSON list of drum pads in a Drum Rack. With `onlyVisible=1`, returns
 * only the 16 pads visible in the matrix view ; otherwise the full 0..127 list.
 * Each entry: { pad_idx, name, note, mute, solo, chain_count } (pad_idx is
 * always the canonical drum_pads index = MIDI note, regardless of mode).
 *
 * @param {number} id
 * @param {number} track
 * @param {number} devIdx
 * @param {number} onlyVisible - 1 to filter to visible_drum_pads.
 */
function lom_get_drum_pads(id, track, devIdx, onlyVisible) {
  _handle(id, function () {
    var rackPath = _rackPath(track, devIdx);
    var rack = new LiveAPI(null, rackPath);
    var listProp = parseInt(onlyVisible) === 1 ? 'visible_drum_pads' : 'drum_pads';
    var count = parseInt(rack.getcount(listProp));
    var out = [];
    for (var i = 0; i < count; i++) {
      var padPath =
        parseInt(onlyVisible) === 1
          ? rackPath + ' visible_drum_pads ' + i
          : _drumPadPath(track, devIdx, i);
      var p = new LiveAPI(null, padPath);
      var note = parseInt(_unwrap(p.get('note')));
      if (isNaN(note) || note < 0) continue;
      out.push({
        pad_idx: note,
        name: String(_unwrap(p.get('name')) || ''),
        note: note,
        mute: Boolean(parseInt(_unwrap(p.get('mute')))),
        solo: Boolean(parseInt(_unwrap(p.get('solo')))),
        chain_count: parseInt(p.getcount('chains')),
      });
    }
    return JSON.stringify(out);
  });
}

